-- table: inventory_moves
CREATE TABLE inventory_moves (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  item_id INTEGER,
  type TEXT DEFAULT 'in',         -- in | out | consume | return | adjust
  qty REAL DEFAULT 0,             -- positive number; sign applied by type
